from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core

class PrismChangeProjectNode(BaseNode):
    name = "Prism: Change Project"
    category = "DCCs"

    def __init__(self):
        super().__init__()
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("project_path", "string", widget_type="file")
        self.add_output("success", "bool")
        self.add_output("active_project", "string")

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        path = inputs.get('project_path') or ''
        if core is None:
            self.log_error("No PrismCore found. Add a prism_core_init node to your graph and connect its exec_out before this node.")
            return {'success': False, 'active_project': ''}
        try:
            core.changeProject(path)
            active = str(getattr(core, 'projectPath', '') or '')
            name = str(getattr(core, 'projectName', '') or '')
            self.log_success(f"Switched to project '{name}' ({active})")
            await self.set_output('exec_out', True)
            return {'success': True, 'active_project': active}
        except Exception as e:
            self.log_error(f"changeProject failed: {e}")
            return {'success': False, 'active_project': ''}

def register_node():
    return PrismChangeProjectNode
